import React, { Component } from 'react';
import styled from 'styled-components';
import { Card, CardBody, CardTitle, CardSubtitle, CardText, CardImg, Row, Col } from 'reactstrap';

const Banner = styled.div`
    position: relative;
    padding: 0em;
`;

const ProfileContainer = styled.div`
    text-align: center;
`
const ProfileImage = styled.img`
    border-radius:50%;
    margin-top:20vh;
`

export class ProfileBanner extends Component {
    static displayName = ProfileBanner.name;

    constructor(props) {
        super(props);

        this.state = {
            priorScrollTop: null,
            initializedContent: <div/>
        }
    }


    render() {
        return (
            <Banner>
                <ProfileContainer> 
                    <h1 className='text-primary'>Hi,</h1>
                    <p className='text-light'>my name is</p>
                    <h1 className='text-bright'>Bradley</h1><h1>Mader</h1>
                    <p className='text-light'>I am a Software Engineer that focuses primarily on web technologies - Specifically as it relates to interconnected real-time experiences.</p>
                </ProfileContainer>
            </Banner>
        );
    }
}
